// // This module takes a 4-bit input symbol and outputs a 16-bit value by concatenating the input symbol twice.
module ofdm_modulator (  
    input wire clk,  
    input wire [3:0] symbol,  
    output reg [15:0] o_output  
);  
    always @(posedge clk) begin  
        o_output <= {symbol, symbol, symbol, symbol};  
    end  
endmodule
